import wave
import sys
import os
import struct

# IMA ADPCM Encoder Table
indexTable = [
    -1, -1, -1, -1, 2, 4, 6, 8,
    -1, -1, -1, -1, 2, 4, 6, 8
]

stepTable = [
    7, 8, 9, 10, 11, 12, 13, 14, 16, 17,
    19, 21, 23, 25, 28, 31, 34, 37, 41, 45,
    50, 55, 60, 66, 73, 80, 88, 97, 107, 118,
    130, 143, 157, 173, 190, 209, 230, 253, 279, 307,
    337, 371, 408, 449, 494, 544, 598, 658, 724, 796,
    876, 963, 1060, 1166, 1282, 1411, 1552, 1707, 1878, 2066,
    2272, 2499, 2749, 3024, 3327, 3660, 4026, 4428, 4871, 5358,
    5894, 6484, 7132, 7845, 8630, 9493, 10442, 11487, 12635, 13899,
    15289, 16818, 18500, 20350, 22385, 24623, 27086, 29794, 32767
]

def encode_adpcm(samples):
    prevsample = 0
    previndex = 0
    code = 0
    
    out_bytes = bytearray()
    
    # Process 2 samples at a time
    for i in range(len(samples)):
        sample = samples[i]
        
        step = stepTable[previndex]
        diff = sample - prevsample
        
        if diff < 0:
            code = 8
            diff = -diff
        else:
            code = 0
            
        mask = 4
        tempstep = step
        
        for bit in range(3):
            if diff >= tempstep:
                code |= mask
                diff -= tempstep
            tempstep >>= 1
            mask >>= 1
            
        # Update state
        diff = 0
        if code & 4: diff += step
        if code & 2: diff += step >> 1
        if code & 1: diff += step >> 2
        
        diff = diff + (step >> 3)
        
        if code & 8:
            prevsample -= diff
        else:
            prevsample += diff
            
        if prevsample > 32767: prevsample = 32767
        elif prevsample < -32768: prevsample = -32768
        
        previndex += indexTable[code & 7]
        if previndex < 0: previndex = 0
        elif previndex > 88: previndex = 88
        
        # Pack nibbles
        if i % 2 == 0:
            out_bytes.append(code) # Store low nibble in lower bits? Wait.
            # Usually: Byte = (HighNibble << 4) | LowNibble
            # If we just appended, we have 1 sample.
            # Let's verify packing order.
            # Standard: 0xHL or 0xLH. 
            # My decoder assumes (i&1) ? (byte >> 4) : (byte & 0x0F)
            # This means Sample 0 is Low Nibble. Sample 1 is High Nibble.
        else:
            # Sample 1
            out_bytes[-1] |= (code << 4)
            
    return out_bytes

def main():
    print("#ifndef VOICE_DATA_H")
    print("#define VOICE_DATA_H")
    print("// Generated by wav2header.py")
    print("")
    
    registry = []
    
    for filename in sys.argv[1:]:
        if not filename.endswith(".wav"): continue
        
        name = os.path.splitext(os.path.basename(filename))[0].upper()
        # Sanitize
        name = "".join(c if c.isalnum() else "_" for c in name)
        
        try:
            w = wave.open(filename, 'rb')
            if w.getnchannels() != 1:
                sys.stderr.write(f"Skipping {filename}: Must be mono\n")
                continue
                
            frames = w.readframes(w.getnframes())
            # Assume 16-bit
            samples = struct.unpack(f"<{len(frames)//2}h", frames)
            
            # Encode
            data = encode_adpcm(samples)
            
            print(f"const uint8_t DATA_{name}[] = {{")
            # Chunk output
            for i in range(0, len(data), 12):
                chunk = data[i:i+12]
                hexs = ", ".join(f"0x{b:02X}" for b in chunk)
                print(f"    {hexs},")
            print("};")
            
            length = len(samples) # Num samples
            registry.append((name, length))
            
        except Exception as e:
            sys.stderr.write(f"Error processing {filename}: {e}\n")
            
    # Create Accessor
    print("")
    # print("const uint8_t* VOICE_DATA[] = {")
    # for name, _ in registry:
    #     print(f"    DATA_{name},")
    # print("};")
    # print("const uint32_t VOICE_LEN[] = {")
    # for _, l in registry:
    #     print(f"    {l},")
    # print("};")
    
    print("#endif")

if __name__ == "__main__":
    main()
